TRENDING = sorted(MODS, key=lambda m: m.get('trending', 0), reverse=True)

CATEGORIES = sorted(set(m['category'] for m in MODS))

def search_mods(query):
    q = (query or '').lower().strip()
    if not q:
        return TRENDING[:50]
    results = []
    for mod in MODS:
        score = 0
        searchable = f"{mod.get('title','')} {mod.get('brand','')} {mod.get('category','')} {mod.get('description','')} {mod.get('why_popular','')}".lower()
        if q in searchable:
            score += 10
        for word in q.split():
            if word and word in searchable:
                score += 3
        if score > 0:
            results.append((score + mod.get('trending', 0), mod))
    results.sort(key=lambda x: x[0], reverse=True)
    return [m for _, m in results]
